import dayjs from 'dayjs';
import { isUndefined } from 'lodash';
import { NotFoundError } from 'routing-controllers';
import { Service } from 'typedi';
import { In } from 'typeorm';

import { SurchargeFeeType } from '@Enums/Hotel';

import { BusinessLogicError } from '@Errors/BusinessLogicError';
import { ErrorCode } from '@Errors/ErrorCode';

import { SurchargeFeeSetting } from '@Entities/SurchargeFeeSetting';
import { Hotel } from '@Entities/Hotel';
import { SurchargeDetail } from '@Entities/types/SurchargeDetail';

import { RangeDate } from '@DBCommon/RangeDate';

import { GeoCountryRepository } from '@Repositories/GeoCountryRepository';
import { HotelRepository } from '@Repositories/HotelRepository';
import { RoomRepository } from '@Repositories/RoomRepository';
import { SeasonRepository } from '@Repositories/SeasonRepository';
import { SurchargeFeeSettingRepository } from '@Repositories/SurchargeFeeSettingRepository';

import { SurchargeRateCalendarService } from '@Services/SurchargeRateCalendarService';
import {
  CreateSurchargeFeeSettingInput,
  SurchargeFeeSettingQueryParamInput,
  UpdateSurchargeFeeSettingInput,
} from '@Services/types/SurchargeFeeSettingInput';

@Service()
export class SurchargeFeeSettingService {
  constructor(
    private readonly repo: SurchargeFeeSettingRepository,
    private readonly seasonRepo: SeasonRepository,
    private readonly hotelRepo: HotelRepository,
    private readonly countryRepo: GeoCountryRepository,
    private readonly roomRepo: RoomRepository,
    private readonly surchargeCalendarService: SurchargeRateCalendarService,
  ) { }

  /**
   * Validate format của periods
   */
  private validatePeriodsFormat(periods: RangeDate[]) {
    if (!periods || !Array.isArray(periods) || periods.length === 0) {
      throw new BusinessLogicError(ErrorCode.PERIODS_REQUIRED);
    }

    for (const dateRange of periods) {
      if (!dateRange.startDate || !dateRange.endDate) {
        throw new BusinessLogicError(ErrorCode.PERIODS_INVALID);
      }

      const startDate = dayjs(dateRange.startDate);
      const endDate = dayjs(dateRange.endDate);

      if (!startDate.isValid() || !endDate.isValid()) {
        throw new BusinessLogicError(ErrorCode.PERIODS_INVALID);
      }

      if (startDate.isAfter(endDate)) {
        throw new BusinessLogicError(ErrorCode.PERIODS_INVALID);
      }
    }
  }

  /**
   * Check trùng lặp dựa trên:
   * - Loại phụ phí (type)
   * - Thị trường khách (countries)
   * - Loại ngày áp dụng (dayType)
   * - Mùa/Sự kiện (seasonId)
   *
   * Nếu các điều kiện trên trùng hoàn toàn thì check:
   * - Mùa trùng mùa (cùng seasonId)
   * - Mùa trùng thời gian tùy chỉnh (periods overlap)
   * - Sự kiện trùng sự kiện (cùng eventId trong season)
   */
  private async checkDuplicate(
    hotelId: number,
    type: SurchargeFeeType,
    countryIds: number[],
    roomIds: number[],
    dayType: string | null,
    seasonId: number | null,
    periods: RangeDate[],
    details?: SurchargeDetail[] | null,
    excludeId?: number,
  ) {
    const duplicate = await this.repo.findDuplicateStrict(
      hotelId,
      type,
      countryIds,
      roomIds,
      dayType,
      seasonId,
      periods,
      details,
      excludeId,
    );

    if (duplicate) {
      throw new BusinessLogicError(ErrorCode.SURCHARGE_FEE_SETTING_DUPLICATE);
    }
  }

  private normalizeDetails(details?: SurchargeDetail[]) {
    if (!details || details.length === 0) return details;
    return [...details].sort((a, b) => {
      if (a.paxType === b.paxType) return a.fromAge - b.fromAge;
      return a.paxType.localeCompare(b.paxType);
    });
  }

  private validateDetails(details?: SurchargeDetail[]) {
    if (!details) return;
    if (details.length === 0) {
      throw new BusinessLogicError(ErrorCode.AGE_RANGE_INVALID);
    }
    //TODO: check rangeAge có bị thiếu ko, ví dụ 0-2,4-10 (thiếu 3)

    const normalized = this.normalizeDetails(details);
    if (!normalized || normalized.length === 0) return;

    const grouped = new Map<string, SurchargeDetail[]>();
    for (const detail of normalized) {
      if (!Number.isFinite(detail.fromAge) || !Number.isFinite(detail.toAge)) {
        throw new BusinessLogicError(ErrorCode.AGE_RANGE_INVALID);
      }
      if (detail.fromAge >= detail.toAge) {
        throw new BusinessLogicError(ErrorCode.AGE_RANGE_INVALID);
      }
      if (!Number.isFinite(detail.amount)) {
        throw new BusinessLogicError(ErrorCode.AGE_RANGE_INVALID);
      }
      const key = detail.paxType;
      const list = grouped.get(key) ?? [];
      list.push(detail);
      grouped.set(key, list);
    }

    for (const ranges of grouped.values()) {
      const sorted = [...ranges].sort((a, b) => a.fromAge - b.fromAge);
      let previousTo: number | null = null;
      for (const range of sorted) {
        if (previousTo !== null && range.fromAge !== previousTo + 1) {
          throw new BusinessLogicError(ErrorCode.AGE_RANGE_INVALID);
        }
        previousTo = range.toAge;
      }
    }
  }

  async create(payload: CreateSurchargeFeeSettingInput) {
    const hotel = await this.hotelRepo.findById(payload.hotelId);
    if (!hotel) throw new NotFoundError(ErrorCode.HOTEL_NOT_FOUND);

    let countries: any[] = [];
    if (payload.countries && payload.countries.length > 0) {
      countries = await this.countryRepo.find({
        where: { id: In(payload.countries) },
      });
      if (countries.length === 0) throw new BusinessLogicError(ErrorCode.COUNTRY_NOT_FOUND);
    }

    let rooms: any[] = [];
    if (payload.roomIds && payload.roomIds.length > 0) {
      rooms = await this.roomRepo.find({
        where: { id: In(payload.roomIds), hotelId: payload.hotelId },
      });
      if (rooms.length === 0) throw new BusinessLogicError(ErrorCode.ROOM_NOT_FOUND);
    }

    const entity = new SurchargeFeeSetting();
    Object.assign(entity, payload);
    entity.countries = countries;
    entity.rooms = rooms;
    entity.hotel = hotel;
    if (payload.details) {
      entity.details = this.normalizeDetails(payload.details);
    }

    if (payload.seasonIds?.length > 0) {
      const seasons = await this.seasonRepo.find({ where: { id: In(payload.seasonIds) } });
      if (!seasons.length) throw new NotFoundError(ErrorCode.SEASON_NOT_FOUND);

      const countryIds = countries.map(c => c.id).sort((a, b) => a - b);
      const roomIds = rooms.map(r => r.id).sort((a, b) => a - b);
      this.validateDetails(entity.details);

      // Check duplicate cho từng season
      for (const season of seasons) {
        this.validatePeriodsFormat(season.periods);
        await this.checkDuplicate(
          entity.hotel.id,
          entity.type,
          countryIds,
          roomIds,
          entity.dayType,
          season.id,
          season.periods,
          entity.details,
        );
      }

      const entities = seasons.map(season => ({
        ...entity,
        season,
        periods: season.periods,
      }));

      const saved = await this.repo.saveMany(entities);
      saved.forEach(setting => {
        if (!setting.rooms || setting.rooms.length === 0) {
          setting.rooms = rooms;
        }
      });
      await this.surchargeCalendarService.rebuildForSettings(saved);
      return saved;

