  async withTransaction<T>(fn: (queryRunner: QueryRunner) => Promise<T>): Promise<T> {
    const queryRunner = this.dataSource.createQueryRunner();
    await queryRunner.connect();
    await queryRunner.startTransaction();
    try {
      const result = await fn(queryRunner);
      await queryRunner.commitTransaction();
      return result;
    } catch (error) {
      await queryRunner.rollbackTransaction();
      throw error;
    } finally {
      await queryRunner.release();
    }
  }

  async findByHotelAndRooms(
    hotelIds: number[],
    roomIds: number[],
    checkInDate: string,
    checkOutDate: string,
  ): Promise<SurchargeRateCalendarRow[]> {
    if (!hotelIds.length) return [];
    const sql = `
      SELECT
        src."hotelId" AS "hotelId",
        src."roomId" AS "roomId",
        src."stayDate" AS "stayDate",
        src."mealPlan" AS "mealPlan",
        src."type" AS "type",
