import { Inject, Service } from 'typedi';
import { DataSource } from 'typeorm';

import { SortDirection } from '@Enums/SortDirection';

import { SurchargeFeeSetting } from '@Entities/SurchargeFeeSetting';
import { SurchargeDetail } from '@Entities/types/SurchargeDetail';

import { RangeDate } from '@DBCommon/RangeDate';

import { BaseOrmRepository } from '@Repositories/BaseOrmRepository';

import { SurchargeFeeSettingQueryParamInput } from '@Services/types/SurchargeFeeSettingInput';

@Service()
export class SurchargeFeeSettingRepository extends BaseOrmRepository<SurchargeFeeSetting> {
  constructor(@Inject('dataSource') dataSource: DataSource) {
    super(dataSource, SurchargeFeeSetting);
  }

  async findAll(query: SurchargeFeeSettingQueryParamInput) {
    const { page = 1, size = 20, hotelId, ownerId, sortBy = 'createdAt', sortDirection = SortDirection.DESC } = query;
    const skip = (page - 1) * size;

    const queryBuilder = this.repo
      .createQueryBuilder('surchargeFeeSetting')
      .leftJoinAndSelect('surchargeFeeSetting.season', 'season')
      .leftJoinAndSelect('surchargeFeeSetting.countries', 'countries')
      .leftJoin('surchargeFeeSetting.rooms', 'rooms').addSelect(['rooms.id', 'rooms.localName', 'rooms.globalName']);

    if (hotelId) {
      queryBuilder.andWhere('surchargeFeeSetting.hotelId = :hotelId', { hotelId });
    }

    if (ownerId) {
      queryBuilder.andWhere('(surchargeFeeSetting.ownerId = :ownerId OR surchargeFeeSetting.ownerId IS NULL)', {
        ownerId,
      });
    }

    const [items, total] = await queryBuilder
      .orderBy(`surchargeFeeSetting.${sortBy}`, sortDirection)
      .skip(skip)
      .take(size)
      .getManyAndCount();
    return { items, total, page, size };
  }

  async findByCountriesAndPeriodsOverlap(hotelId: number, countryIds: number[], periods: RangeDate[]) {
    if (!periods || periods.length === 0) return [];

    const queryBuilder = this.repo
      .createQueryBuilder('surchargeFeeSetting')
      .leftJoinAndSelect('surchargeFeeSetting.season', 'season')
      .leftJoinAndSelect('surchargeFeeSetting.countries', 'countries')
      .where('surchargeFeeSetting.hotelId = :hotelId', { hotelId })
      .andWhere('countries.id IN (:...countryIds)', { countryIds });

    const periodConditions = periods.map((period, index) => {
      return `EXISTS (
        SELECT 1 FROM jsonb_array_elements(surchargeFeeSetting.periods) AS surcharge_period
        WHERE (surcharge_period->>'startDate')::timestamp >= :priceStart${index}
        AND (surcharge_period->>'endDate')::timestamp <= :priceEnd${index}
      )`;
    });

    queryBuilder.andWhere(`(${periodConditions.join(' OR ')})`);

    periods.forEach((period, index) => {
      queryBuilder.setParameter(`priceStart${index}`, period.startDate);
      queryBuilder.setParameter(`priceEnd${index}`, period.endDate);
    });

    return queryBuilder.getMany();
  }

  /**
   * Check trùng lặp strict dựa trên:
   * - Loại phụ phí (type)
   * - Thị trường khách (countries)
   * - Loại ngày áp dụng (dayType)
   *
   * Nếu các điều kiện trên trùng hoàn toàn thì check thời gian/mùa/sự kiện:
   * - Mùa trùng mùa (cùng seasonId)
   * - Mùa thông thường trùng thời gian tùy chỉnh (season có periods overlap với periods tùy chỉnh)
   * - Sự kiện trùng sự kiện (cùng eventId trong season) - KHÔNG trùng với thời gian tùy chỉnh
   * - Thời gian tùy chỉnh trùng thời gian tùy chỉnh (periods overlap)
   * - Thời gian tùy chỉnh trùng mùa thông thường (periods overlap với season.periods)
   */
  async findDuplicateStrict(
    hotelId: number,
    type: string,
    countryIds: number[],
    roomIds: number[],
    dayType: string | null,
    seasonId: number | null,
    periods: RangeDate[],
    details?: SurchargeDetail[] | null,
    excludeId?: number,
  ) {
    const qb = this.repo.createQueryBuilder('sfs').leftJoinAndSelect('sfs.season', 'season');

    // Check các điều kiện bắt buộc
    qb.where('sfs.hotelId = :hotelId', { hotelId })
      .andWhere('sfs.type = :type', { type })
      .andWhere('sfs.dayType IS NOT DISTINCT FROM :dayType', {
        dayType: dayType ?? null,
      });

    if (details && details.length > 0) {
      const valuesSql = details.map((_, i) => `(:fromAge${i}, :toAge${i}, :paxType${i})`).join(', ');
      qb.andWhere(
        `(
          COALESCE(jsonb_array_length(sfs."details"), 0) = 0
          OR EXISTS (
            SELECT 1
            FROM jsonb_array_elements(sfs."details") sfs_detail,
                 (VALUES ${valuesSql}) AS input_details(from_age, to_age, pax_type)
            WHERE (sfs_detail->>'paxType') = input_details.pax_type
              AND (sfs_detail->>'fromAge')::int <= input_details.to_age::int
              AND (sfs_detail->>'toAge')::int >= input_details.from_age::int
          )
        )`,
      );

      details.forEach((detail, index) => {
        qb.setParameter(`fromAge${index}`, detail.fromAge);
        qb.setParameter(`toAge${index}`, detail.toAge);
        qb.setParameter(`paxType${index}`, detail.paxType);
      });
    }

    // Exclude record hiện tại khi update
    if (excludeId) {
      qb.andWhere('sfs.id != :excludeId', { excludeId });
    }

    // Check exact match cho countries (M2M relation)
    // Tối ưu: Dùng subquery với ARRAY_AGG thay vì JOIN
    qb.andWhere(
      `ARRAY(
        SELECT sfsc."geoCountryId"
        FROM surcharge_fee_setting_countries sfsc
        WHERE sfsc."surchargeFeeSettingId" = sfs.id
        ORDER BY sfsc."geoCountryId"
      ) = :countryIds::int[]`,
      { countryIds: countryIds.sort((a, b) => a - b) },
    );

    // Check exact match cho rooms (M2M relation)
    qb.andWhere(
      `ARRAY(
        SELECT sfsr."roomId"
        FROM surcharge_fee_setting_rooms sfsr
        WHERE sfsr."surchargeFeeSettingId" = sfs.id
        ORDER BY sfsr."roomId"
      ) = :roomIds::int[]`,
      { roomIds: roomIds.sort((a, b) => a - b) },
    );

    // Check mùa/sự kiện/thời gian tùy chỉnh
    if (seasonId) {
      // Trường hợp có season: check trùng với
      // 1. Các record cùng seasonId (bao gồm cả event trong season)
      // 2. NẾU là mùa thông thường (không phải event): Check các record thời gian tùy chỉnh overlap
      //    NẾU là mùa sự kiện: KHÔNG check với thời gian tùy chỉnh (event chỉ trùng event)
      qb.andWhere(
        `(
          sfs.seasonId = :seasonId
          OR (
            sfs.seasonId IS NULL
            AND EXISTS (
              SELECT 1
              FROM season input_season,
                   jsonb_array_elements(sfs.periods) sfs_period,
                   jsonb_array_elements(input_season.periods) input_season_period
              WHERE input_season.id = :seasonId
                AND input_season."eventId" IS NULL
                AND (sfs_period->>'startDate')::timestamp < (input_season_period->>'endDate')::timestamp
                AND (sfs_period->>'endDate')::timestamp > (input_season_period->>'startDate')::timestamp
            )
          )
        )`,
        { seasonId },
      );
    } else if (periods && periods.length > 0) {
      // Trường hợp thời gian tùy chỉnh
      // Check overlap với:
      // 1. Các record thời gian tùy chỉnh khác (seasonId IS NULL)
      // 2. Các record có mùa THÔNG THƯỜNG (không phải event) có periods overlap

      // Tối ưu: Gộp tất cả periods thành 1 điều kiện với VALUES để tránh lặp query
      qb.andWhere(
        `(
          (sfs.seasonId IS NULL AND EXISTS (
            SELECT 1
            FROM jsonb_array_elements(sfs.periods) sfs_period,
                 (VALUES ${periods.map((_, i) => `(:startDate${i}, :endDate${i})`).join(', ')}) AS input_periods(start_date, end_date)
            WHERE (sfs_period->>'startDate')::timestamp < input_periods.end_date::timestamp
              AND (sfs_period->>'endDate')::timestamp > input_periods.start_date::timestamp
          ))
          OR (
            sfs.seasonId IS NOT NULL
            AND season."eventId" IS NULL
            AND EXISTS (
              SELECT 1
              FROM jsonb_array_elements(season.periods) season_period,
                   (VALUES ${periods.map((_, i) => `(:startDate${i}, :endDate${i})`).join(', ')}) AS input_periods(start_date, end_date)
              WHERE (season_period->>'startDate')::timestamp < input_periods.end_date::timestamp
                AND (season_period->>'endDate')::timestamp > input_periods.start_date::timestamp
            )
          )
        )`,
      );

      periods.forEach((period, index) => {
        qb.setParameter(`startDate${index}`, period.startDate);
        qb.setParameter(`endDate${index}`, period.endDate);
      });
    }

    return qb.getOne();
  }
}

